import fs from 'node:fs';
import path from 'node:path';
import YAML from 'yaml';
import { resolveShared, resolveStack } from './profiles.js';
import { generatedRoot } from './paths.js';
/**
 * Generate the thin VS Code agent body + Copilot CLI AGENTS.md for a profile.
 * "Thin" means we do not inline the shared/stack/context content — we emit a
 * table pointing the agent at the absolute paths so it can read on demand with
 * its `read` tool (same lazy-loading shape Claude gets from @-imports).
 *
 * Returns absolute paths to both artifacts. They are written under
 * ~/.agent-toolbox/generated/<profile>/ so that a later copy to the VS Code
 * prompts folder / Codex home / etc. uses a stable source path, regardless of
 * where the CLI package itself was installed.
 */
export function generate(profile) {
    const outDir = path.join(generatedRoot(), profile.name);
    fs.mkdirSync(outDir, { recursive: true });
    const body = composeBody(profile);
    const frontmatter = composeFrontmatter(profile);
    const agentMd = normalise(path.join(outDir, `${profile.name}.agent.md`));
    const agentsMd = normalise(path.join(outDir, 'AGENTS.md'));
    fs.writeFileSync(agentMd, `${frontmatter}\n<!-- GENERATED by agent-toolbox — do not edit -->\n<!-- profile: ${profile.name} -->\n${body}\n`, 'utf8');
    fs.writeFileSync(agentsMd, `<!-- GENERATED by agent-toolbox — do not edit -->\n<!-- profile: ${profile.name} -->\n\n# ${profile.manifest.copilot.description ?? profile.manifest.description ?? profile.name}\n${body}\n`, 'utf8');
    return { agentMd, agentsMd };
}
function composeFrontmatter(profile) {
    const { manifest } = profile;
    const name = manifest.copilot.name ?? profile.name;
    const description = manifest.copilot.description ?? manifest.description ?? `${profile.name} agent`;
    const lines = ['---', `name: ${name}`, `description: ${description}`];
    if (manifest.copilot.argumentHint) {
        lines.push(`argument-hint: ${manifest.copilot.argumentHint}`);
    }
    if (manifest.copilot.tools && manifest.copilot.tools.length > 0) {
        const toolList = manifest.copilot.tools.map((t) => `'${t}'`).join(', ');
        lines.push(`# tools: [${toolList}] # suggested (uncomment + adjust to VS Code's tool IDs)`);
    }
    if (manifest.copilot.model) {
        lines.push(`model: ${manifest.copilot.model}`);
    }
    lines.push('---', '');
    return lines.join('\n');
}
function composeBody(profile) {
    const lines = [];
    lines.push(`\nYou are the **${profile.name}** agent.\n`);
    lines.push('Load context on demand using the `read` tool — do not rely on generic knowledge when a project guideline exists. The files below are the authoritative source for this profile.\n');
    if (profile.manifest.projectContext) {
        const ctxPath = path.join(profile.dir, profile.manifest.projectContext);
        if (!fs.existsSync(ctxPath)) {
            throw new Error(`project_context not found: ${ctxPath}`);
        }
        lines.push('## Always read at the start of any coding task\n');
        lines.push(`- \`${normalise(ctxPath)}\` — project architecture, commands, and non-negotiable rules.\n`);
    }
    lines.push('## Load when the task enters this scope\n');
    lines.push('| Scope hint (from the file) | Read |');
    lines.push('|---|---|');
    for (const entry of profile.manifest.shared) {
        const p = resolveShared(entry);
        lines.push(`| ${frontmatterDescription(p) ?? entry} | \`${normalise(p)}\` |`);
    }
    for (const stack of profile.manifest.stacks) {
        const stackDir = resolveStack(stack);
        const files = fs
            .readdirSync(stackDir)
            .filter((f) => f.endsWith('.md'))
            .sort();
        for (const f of files) {
            const p = path.join(stackDir, f);
            lines.push(`| ${frontmatterDescription(p) ?? `${stack}/${f}`} | \`${normalise(p)}\` |`);
        }
    }
    lines.push('');
    lines.push('## Rules\n');
    lines.push('- Read the matching file(s) **before** acting; when a task spans multiple scopes, load every applicable file.');
    lines.push('- Follow the file literally — it is the source of truth. When in doubt, re-read.');
    lines.push('- Declare a task done only after running the checks the guideline prescribes (`npm test`, `./gradlew test`, lint, coverage threshold, etc.).');
    lines.push('- Never copy agent-config files (this agent file, CLAUDE.md, the toolbox) into the target project repo.');
    return lines.join('\n');
}
function frontmatterDescription(file) {
    const content = fs.readFileSync(file, 'utf8');
    const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
    if (!match)
        return undefined;
    try {
        const fm = YAML.parse(match[1]) ?? {};
        if (typeof fm.description === 'string')
            return fm.description;
    }
    catch {
        // ignore malformed frontmatter
    }
    return undefined;
}
function normalise(p) {
    return p.split(path.sep).join('/');
}
